const TechStack = () => {
  const [iconSize, setIconSize] = useState(40);
  const [iconUtama, setIconUtama] = useState(35);
  const [radius, setRadius] = useState([50, 100, 155, 205, 250]);

  useEffect(() => {
    function handleResize() {
      const height = window.innerWidth;

      if (height <= 533) {
        setIconSize(25);
        setIconUtama(23);
        setRadius([28, 60, 93, 125, 155]);
      } else if (height <= 880) {
        setIconSize(30);
        setIconUtama(28);
        setRadius([40, 80, 120, 160, 200]);
      } else {
        setIconSize(40);
        setIconUtama(35);
        setRadius([50, 100, 155, 205, 250]);
      }
    }

    handleResize();
    window.addEventListener("resize", handleResize);

    return () => window.removeEventListener("resize", handleResize);
  }, []);

  return (
    <div className="relative s  flex h-[600px] w-full flex-col items-center justify-center ">
      <OrbitingCircles iconSize={iconSize} radius={radius[1]}>
        <Icons.react />
        <Icons.nextJS />
        <Icons.laravel />
      </OrbitingCircles>
      <OrbitingCircles iconSize={iconSize} radius={radius[2]}>
        <Icons.mui />
        <Icons.shadcn />
        <Icons.tailwind />
        <Icons.flowbite />
        <Icons.bootstrap />
      </OrbitingCircles>
      <OrbitingCircles iconSize={iconSize} radius={radius[3]}>
        <Icons.mysql />
        <Icons.postgresql />
        <Icons.prisma />
      </OrbitingCircles>
      <OrbitingCircles iconSize={iconSize} radius={radius[4]}>
        <Icons.chatGPT />
        <Icons.claude />
        <Icons.docker />
        <Icons.git />
        <Icons.github />
      </OrbitingCircles>
      <OrbitingCircles
        iconSize={iconUtama}
        radius={radius[0]}
        reverse
        speed={2}
      >
        <Icons.php />
        <Icons.typeScript />
        <Icons.javaScript />
        <Icons.golang />
      </OrbitingCircles>
    </div>
  );
};

export default TechStack;
